Literal.Value:
'{
  "description": "Top Produtos por Receita (Top 8) — dProduto[NOME] + _Medidas[Total Receita]",
  "data": { "name": "dataset" },
  "width": "container",
  "height": "container",
  "background": "transparent",
  "transform": [
    { "window": [{ "op": "rank", "as": "rnk" }], "sort": [{ "field": "Total Receita", "order": "descending" }] },
    { "filter": "datum.rnk <= 8" }
  ],
  "title": {
    "text": "Top Produtos por Receita",
    "subtitle": "Top 8 · R$",
    "anchor": "start",
    "color": "#ffffff",
    "fontSize": 15,
    "fontWeight": 600,
    "subtitleColor": "#8888A8",
    "subtitleFontSize": 11,
    "subtitlePadding": 4,
    "offset": 6,
    "dx": 2
  },
  "encoding": {
    "y": {
      "field": "NOME",
      "type": "nominal",
      "sort": { "field": "Total Receita", "order": "descending" },
      "title": null,
      "axis": { "labelColor": "#e5e7eb", "domainColor": "transparent", "tickColor": "transparent", "labelFontSize": 11, "labelLimit": 200 }
    },
    "x": {
      "field": "Total Receita",
      "type": "quantitative",
      "title": null,
      "axis": { "labels": false, "grid": false, "domainColor": "transparent", "tickColor": "transparent" }
    }
  },
  "layer": [
    {
      "mark": { "type": "bar", "cornerRadiusEnd": 6, "height": 13 },
      "params": [
        { "name": "sel", "select": { "type": "point", "on": "click", "fields": ["NOME"], "clear": "dblclick" } }
      ],
      "encoding": {
        "color": {
          "field": "Total Receita",
          "type": "quantitative",
          "scale": { "range": ["rgba(139,92,246,0.30)", "#8B5CF6"] },
          "legend": null
        },
        "tooltip": [
          { "field": "NOME", "type": "nominal", "title": "Produto" },
          { "field": "Total Receita", "type": "quantitative", "title": "Receita (R$)", "format": ",.2f" }
        ]
      }
    },
    {
      "mark": { "type": "text", "align": "left", "dx": 6, "color": "#9ca3af", "fontSize": 11 },
      "encoding": { "text": { "field": "Total Receita", "type": "quantitative", "format": ",.0f" } }
    }
  ],
  "config": { "view": { "stroke": "transparent" } }
}'
